import React, { useState } from "react";
import {
	Container,
	Segment,
	Item,
	Grid,
	Accordion,
	Label,
	Ref
} from "semantic-ui-react";

import Tabs from "./Tabs";
import StickyBox from "./StickyBox";

function CourseSummary(props) {
	const [contextRef, setContextRef] = useState(null);
	const handleContextRef = e => setContextRef(e);
	const {
		title,
		slug,
		image,
		instructors,
		description,
		shortDescription,
		categories,
		skillLevel
	} = props;
	const instructor = instructors.map(y => y.fields.instructor);
	const category = categories.map(y => y.fields);
	const panels = false;

	const items = [
		{
			header: title,
			description: shortDescription,
			meta: skillLevel,
			extra: instructor
		}
	];
	const TabsContent = [
		{ title: "Overview", content: "A7a1" },
		{ title: "Content", content: "A7a1" },
		{ title: "Requirements", content: "A7a1" },
		{ title: "Review", content: "A7a1" }
	];
	return (
		<Segment basic as={Container} >
			<Ref innerRef={handleContextRef} style={{ height: "600px" }}>
				<Grid padded={"vertically"}>
					<Grid.Row>
						<Grid.Column width="4">
							<StickyBox
								contextRef={contextRef}
								slug={slug}
								image={image.fields.file.url}
							/>
						</Grid.Column>
						<Grid.Column width="12">
							{category.map((y, i) => (
								<Label color={"grey"} key={i}>
									{" "}
									{y.title}
								</Label>
							))}
							<Item.Group items={items} />
							<div>{description}</div>
							{panels ? (
								<Accordion
									exclusive={false}
									fluid
									styled
									panels={panels}
								/>
							) : (
								"fuck"
							)}
							<Tabs TabsContent={TabsContent} />
						</Grid.Column>
					</Grid.Row>
					<Grid.Row>
						<Grid.Column />
					</Grid.Row>
				</Grid>
			</Ref>
		</Segment>
	);
}
export default CourseSummary;
