import React, { useState, useEffect } from "react";
import { getCourseBySlug } from "../lib/contentful";
import CourseSummary from "../components/summary/CourseSummary";
// import { Segment, Container, Button } from "semantic-ui-react";

function Course({ match }) {
	const [course, setCourse] = useState(null);
	useEffect(() => {
		getCourseBySlug(match.params.id).then(x => setCourse(x));
	}, []);
	return course ? <CourseSummary {...course} /> : "a7a";
}


export default Course;
